// src/components/payment/Payment.jsx
import { useState, useEffect } from "react";
import './Payment.css';

const AmountForm = ({ amount = 0, transportData }) => {
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState("");
  const [paymentData, setPaymentData] = useState(null);

  // Auto-submit when amount is provided
  useEffect(() => {
    if (amount && amount >= 10 && amount <= 50000) {
      handleSubmit(amount);
    }
  }, [amount]);

  const handleSubmit = async (submitAmount) => {
    if (!submitAmount || submitAmount < 10 || submitAmount > 50000) {
      setError("Amount must be between ₹10 and ₹50,000");
      return;
    }

    setIsLoading(true);
    setError("");

    try {
      const token = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJfaWQiOiI2NzEwODhmZjM4ZGJhNzhhZDY2YjVmZWIiLCJwaG9uZU51bWJlciI6ODgxMDMwMDcyNCwiZW1haWwiOiJzeTI0MTUyN0BnbWFpbC5jb20iLCJyb2xlIjoiY2hhZ2Fuc0VtcGxveWVlMiIsImxvZ2luSWQiOiJmOGUzOWRhOC03MmQ2LTRmNTUtYWJlMC0xM2Q5YWIxMjJmZTkiLCJpYXQiOjE3NjkxNDM0NDUsImV4cCI6MTc3NjkxOTQ0NX0.Y8_yAqXxKhw7Hijfn5zJkHfWDHqijjRyxDom2XwqzFs";
      
      if (!token) {
        setError("Authentication required. Please login.");
        setIsLoading(false);
        return;
      }

      const response = await fetch(
        `https://chagans.com/payment/addMoneyTen`,
        {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
            "Authorization": `Bearer ${token}`,
            "Accept": "application/json"
          },
          body: JSON.stringify({
            amount: submitAmount, 
            transportData: {
              ...transportData,
              trackingId: `TRK${Math.floor(100000 + Math.random() * 900000)}`,
            },
            mobile: "7983920962",
            apiType: "API",
          }),
        }
      );

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const data = await response.json();
      console.log("Payment response data:", data);
      
      if (data.success) {
        setPaymentData(data.data);
        
        // Automatically create and submit form to redirect to payment page
        const form = document.createElement('form');
        form.method = 'POST';
        form.action = data.data.APIURL;
        form.target = '_blank'; // Opens in new tab
        
        // Add all payment data as hidden inputs
        Object.entries(data.data).forEach(([key, value]) => {
          if (key !== 'APIURL' && value) {
            const input = document.createElement('input');
            input.type = 'hidden';
            input.name = key.toUpperCase();
            input.value = value;
            form.appendChild(input);
          }
        });
        
        document.body.appendChild(form);
        form.submit();
        document.body.removeChild(form);
        
      } else {
        setError(data.message || "Payment failed. Please try again.");
      }
    } catch (err) {
      console.error('Payment error:', err);
      setError("Network error. Please check your connection.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="amount-form-container">
      {/* Loading State */}
      {isLoading && (
        <div className="loading-indicator">
          <div className="spinner"></div>
          <p>Redirecting to payment gateway...</p>
        </div>
      )}

      {/* Error Message */}
      {error && (
        <div className="error-message">
          <p>{error}</p>
          <button 
            onClick={() => handleSubmit(amount)}
            className="retry-button"
            style={{
              marginLeft: '10px',
              padding: '5px 10px',
              background: '#dc2626',
              color: 'white',
              border: 'none',
              borderRadius: '4px',
              cursor: 'pointer'
            }}
          >
            Retry
          </button>
        </div>
      )}

      {/* Message when redirected */}
      {paymentData && !isLoading && !error && (
        <div className="success-message">
          <p>✅ Redirecting to payment gateway...</p>
          <p style={{fontSize: '12px', marginTop: '5px'}}>
            If not redirected, <button 
              onClick={() => window.open(paymentData.APIURL, '_blank')}
              style={{background: 'none', border: 'none', color: '#2563eb', textDecoration: 'underline', cursor: 'pointer'}}
            >click here</button>
          </p>
        </div>
      )}
    </div>
  );
};

export default AmountForm;
